// Parse incoming leads for Apollo sequence outreach
const input = $input.item.json;
let data = input.body || input;
if (typeof data === 'string') data = JSON.parse(data);

const leads = data.leads || [];
const tone = data.tone || 'professional';
const additionalContext = data.additional_context || '';

// Apollo config passed from frontend
const apolloApiKey = data.apollo_api_key || '';
const emailAccountId = data.email_account_id || '';

// MSI Service → Apollo Sequence ID mapping
// Configure these IDs after creating sequences in Apollo UI
const sequenceMap = data.sequence_map || {
  'Cybersecurity': 'CONFIGURE_SEQUENCE_ID',
  'Cloud Migration': 'CONFIGURE_SEQUENCE_ID',
  'AI Integration': 'CONFIGURE_SEQUENCE_ID',
  'IT Infrastructure Modernization': 'CONFIGURE_SEQUENCE_ID',
  'Managed IT Services': 'CONFIGURE_SEQUENCE_ID',
  'Data Analytics': 'CONFIGURE_SEQUENCE_ID',
  'Network Security': 'CONFIGURE_SEQUENCE_ID',
  'Digital Transformation': 'CONFIGURE_SEQUENCE_ID'
};

console.log(`Processing ${leads.length} leads for Apollo sequence outreach`);

// Output one item per lead
const items = leads.map(lead => ({
  json: {
    ...lead,
    tone,
    additional_context: additionalContext,
    apollo_api_key: apolloApiKey,
    email_account_id: emailAccountId,
    sequence_map: sequenceMap
  }
}));

return items;

