// Parse AI output and map to Apollo sequence
const output = $json.output;
const lead = $('Parse Leads Input').item.json;

let aiResult;
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  aiResult = JSON.parse(jsonMatch ? jsonMatch[0] : output);
} catch (e) {
  aiResult = {
    matched_service: 'Managed IT Services',
    reason: 'Default fallback - could not parse AI response'
  };
}

const serviceName = aiResult.matched_service || 'Managed IT Services';
const sequenceMap = lead.sequence_map || {};
const sequenceId = sequenceMap[serviceName] || sequenceMap['Managed IT Services'] || 'CONFIGURE_SEQUENCE_ID';

console.log(`Lead ${lead.first_name} ${lead.last_name} → ${serviceName} → Sequence: ${sequenceId}`);

return [{
  json: {
    // Lead data
    lead_id: lead.id,
    first_name: lead.first_name,
    last_name: lead.last_name,
    email: lead.email,
    title: lead.title,
    company_name: lead.company_name,
    industry: lead.industry,
    city: lead.city,
    state: lead.state,
    website: lead.website,
    // AI result
    matched_service: serviceName,
    match_reason: aiResult.reason || '',
    // Apollo config
    apollo_api_key: lead.apollo_api_key,
    email_account_id: lead.email_account_id,
    sequence_id: sequenceId
  }
}];

// Extract Apollo contact ID from response
const response = $json;
const prevData = $('Map Service to Sequence').item.json;

let contactId = '';
let contactCreated = false;

try {
  const body = response.body || response;
  const contact = body.contact || body;
  contactId = contact.id || '';
  contactCreated = true;
  console.log(`Apollo contact created/found: ${contactId} for ${prevData.first_name} ${prevData.last_name}`);
} catch (e) {
  console.error('Error extracting Apollo contact ID:', e.message);
}

return [{
  json: {
    ...prevData,
    apollo_contact_id: contactId,
    contact_created: contactCreated
  }
}];

// Parse Apollo add-to-sequence response
const response = $json;
const prevData = $('Extract Contact ID').item.json;

let addedToSequence = false;
let skippedReason = '';

try {
  const body = response.body || response;

  // Check if contact was added successfully
  if (body.contacts && body.contacts.length > 0) {
    addedToSequence = true;
    console.log(`Contact ${prevData.apollo_contact_id} added to sequence ${prevData.sequence_id}`);
  }

  // Check if contact was skipped
  if (body.skipped_contact_ids) {
    const skipped = body.skipped_contact_ids;
    if (skipped[prevData.apollo_contact_id]) {
      skippedReason = skipped[prevData.apollo_contact_id];
      console.log(`Contact ${prevData.apollo_contact_id} skipped: ${skippedReason}`);
    }
  }
} catch (e) {
  console.error('Error parsing sequence response:', e.message);
}

const status = addedToSequence ? 'added_to_sequence' : (skippedReason ? `skipped:${skippedReason}` : 'error');

return [{
  json: {
    lead_id: prevData.lead_id,
    to_email: prevData.email,
    to_name: `${prevData.first_name} ${prevData.last_name}`,
    company: prevData.company_name,
    service: prevData.matched_service,
    match_reason: prevData.match_reason,
    apollo_contact_id: prevData.apollo_contact_id,
    sequence_id: prevData.sequence_id,
    status: status,
    skipped_reason: skippedReason
  }
}];
